+        M: 12,
+        efConstruction: 100,
+        efSearch: 50,
+        quantization: 'int8'
+      },
+      'high_accuracy': {
+        M: 32,
+        efConstruction: 400,
+        efSearch: 200,
+        quantization: 'float32'
+      },
+      'balanced': {
+        M: 16,
+        efConstruction: 200,
+        efSearch: 100,
+        quantization: 'float16'
+      },
+      'memory_constrained': {
+        M: 8,
+        efConstruction: 50,
+        efSearch: 30,
+        quantization: 'int4'
+      }
+    };
+
+    return optimizations[workloadType] || optimizations['balanced'];
+  }
+
+  // Performance benchmarks
+  measureSearchPerformance(indexSize, dimensions) {
+    const baselineLinear = indexSize * dimensions; // O(n*d)
+    const hnswComplexity = Math.log2(indexSize) * this.defaultParams.M;
+
+    return {
