+
+    // Collect peer states
+    const peerStates = await Promise.all(
+      peers.map(peer => this.fetchPeerState(peer))
+    );
+
+    // Merge states
+    const mergedState = await syncer.merge(localState, peerStates);
+
+    // Resolve conflicts
