+      prSum += pr;
+      if (pr > prMax) { prMax = pr; prMaxId = id; }
+    }
+  }
+
+  // Top patterns by composite score
+  const topPatterns = (ranked && ranked.entries || []).slice(0, 10).map((e, i) => ({
