+  }
+
+  if (delta) {
+    console.log(`  Last Delta (${delta.elapsed} ago)`);
+    const sign = v => v > 0 ? `+${v}` : `${v}`;
+    console.log(`    Nodes:      ${sign(delta.nodes)}`);
+    console.log(`    Edges:      ${sign(delta.edges)}`);
